export function formatSessionAsNote(t){const e=new Date(t.startedAt).toLocaleString("en-US",{month:"short",day:"numeric",year:"numeric",hour:"numeric",minute:"2-digit"}),n=t.endedAt-t.startedAt,o=`${Math.floor(n/6e4)}:${Math.floor(n%6e4/1e3).toString().padStart(2,"0")}`;let r=`Platform: ${t.platform} | Duration: ${o}\n\n`;return t.context&&t.context.trim().length>0&&(r+=`Context: ${t.context.trim()}\n\n`),r+="## Transcript\n\n",t.transcript&&t.transcript.length>0?t.transcript.forEach(t=>{const e=new Date(t.timestamp).toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit"}),n="you"===t.speaker?"You":"Them";r+=`[${e}] ${n}: ${t.text}\n`}):r+="*No transcription recorded.*\n",t.aiResponses&&t.aiResponses.length>0&&(r+="\n## AI Suggestions\n\n",t.aiResponses.forEach(t=>{r+=`**Q: ${t.question}**\n${t.response}\n\n`})),{id:t.id||`meeting_${Date.now()}`,title:t.title||`Meeting — ${e}`,body:r.trim(),createdAt:Date.now(),updatedAt:Date.now(),pinned:!1,reminderAt:null,tags:["meeting",(t.platform||"Unknown").toLowerCase().replace(/\s+/g,"-")],deleted:!1}}